import ChatForm from "../../components/Chat/ChatForm";
import TextInput from "../../components/Input/TextInput";

const AddFriend = () => {
  return (
    <div>
      <header>
        <h2>ADD FRIEND</h2>
        <form>
          <div>You can add friends with their username.</div>
          <TextInput></TextInput>
          <ChatForm></ChatForm>
        </form>
      </header>
    </div>
  );
};

export default AddFriend;
